import{c as t,Q as a,j as n,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"The Last Harness You'll Ever Build: Meta-Harness Evolution via Two-Level Automation","description":"","frontmatter":{"title":"The Last Harness You'll Ever Build: Meta-Harness Evolution via Two-Level Automation","authors":"Haebin Seong, Li Yin, Haoran Zhang, Zhan Shi","published":"2026-04-29T00:00:00.000Z","source":"https://arxiv.org/abs/2604.21003"},"headers":[],"relativePath":"research/agent-harness/references/2026-04-29-last-harness-youll-ever-build-2604-21003.md","filePath":"research/agent-harness/references/2026-04-29-last-harness-youll-ever-build-2604-21003.md","lastUpdated":1779935873000}`),o={name:"research/agent-harness/references/2026-04-29-last-harness-youll-ever-build-2604-21003.md"};function r(i,e,l,p,d,c){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="the-last-harness-you-ll-ever-build-meta-harness-evolution-via-two-level-automation" tabindex="-1">The Last Harness You&#39;ll Ever Build: Meta-Harness Evolution via Two-Level Automation <a class="header-anchor" href="#the-last-harness-you-ll-ever-build-meta-harness-evolution-via-two-level-automation" aria-label="Permalink to &quot;The Last Harness You&#39;ll Ever Build: Meta-Harness Evolution via Two-Level Automation&quot;">​</a></h1><p><strong>Authors</strong>: Haebin Seong, Li Yin, Haoran Zhang, Zhan Shi <strong>Published</strong>: April 22 – May 1, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2604.21003" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.21003</a><strong>arXiv ID</strong>: 2604.21003 <strong>Categories</strong>: cs.AI, cs.LG, cs.SE</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>AI agents deployed on complex, domain-specific workflows require painstaking harness engineering—designing prompts, tools, orchestration logic, and evaluation criteria. This paper presents a two-level framework automating this process. The Harness Evolution Loop optimizes a worker agent&#39;s harness for a single task through cycles of execution, adversarial evaluation, and modification. The Meta-Evolution Loop then optimizes the evolution blueprint itself across diverse tasks, learning how to rapidly adapt agents to novel domains without human engineering.</p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>Recent work demonstrates that carefully designed scaffolding—execution environments, feedback loops, evaluation criteria, and context management—dramatically amplifies agent capabilities. However, these harnesses require &quot;highly intensive, specialized human engineering&quot; with deep domain expertise and significant iteration.</p><p>Existing automated prompt optimization methods exist, but they don&#39;t address the full harness—tools, orchestration logic, infrastructure, and their interactions.</p><p>The paper proposes automating improvement cycles through:</p><ol><li><strong>Harness Evolution Loop</strong> — optimizes a worker agent&#39;s harness ℋ for a single task</li><li><strong>Meta-Evolution Loop</strong> — optimizes the evolution blueprint itself across diverse tasks</li></ol><hr><h2 id="_2-the-harness-evolution-loop" tabindex="-1">2. The Harness Evolution Loop <a class="header-anchor" href="#_2-the-harness-evolution-loop" aria-label="Permalink to &quot;2. The Harness Evolution Loop&quot;">​</a></h2><h3 id="_2-1-defining-the-agent-harness" tabindex="-1">2.1 Defining the Agent Harness <a class="header-anchor" href="#_2-1-defining-the-agent-harness" aria-label="Permalink to &quot;2.1 Defining the Agent Harness&quot;">​</a></h3><p><strong>Agent = Model + Harness</strong></p><p>A harness encompasses everything except the model itself. Components:</p><ul><li>System prompts and task prompts (goals, success criteria, examples)</li><li>Tools and skills with descriptions</li><li>Bundled infrastructure (filesystem, sandboxes, browsers, observability)</li><li>Orchestration logic (subagent spawning, handoffs, routing, feedback loops)</li><li>Hooks and middleware (execution guarantees, compaction, verification)</li><li>Model configurations (choice, parameters, routing rules)</li></ul><p>Examples: AdaL, Claude Code, Codex (software engineering harnesses), OpAgent (web navigation harness). The harness—not the model—determines what agents perceive, how they act, and how work is orchestrated and verified.</p><h3 id="_2-2-task-definitions" tabindex="-1">2.2 Task Definitions <a class="header-anchor" href="#_2-2-task-definitions" aria-label="Permalink to &quot;2.2 Task Definitions&quot;">​</a></h3><p>A task <strong>t = (I, S)</strong> consists of:</p><ul><li><strong>Instructions I</strong> — concrete goal for the worker agent</li><li><strong>Success criteria S</strong> — checklist of verifiable completion conditions</li></ul><h3 id="_2-3-worker-agent" tabindex="-1">2.3 Worker Agent <a class="header-anchor" href="#_2-3-worker-agent" aria-label="Permalink to &quot;2.3 Worker Agent&quot;">​</a></h3><p>The Worker Agent <strong>W_ℋ</strong> is the agent under optimization, parameterized by harness ℋ.</p><p>Interface: <code>W_ℋ.execute(t)</code> → given task t, worker receives instructions I, interacts with target environment through tools, produces execution trace τ containing observations, action logs, and timing data.</p><h3 id="_2-4-evaluator-agent" tabindex="-1">2.4 Evaluator Agent <a class="header-anchor" href="#_2-4-evaluator-agent" aria-label="Permalink to &quot;2.4 Evaluator Agent&quot;">​</a></h3><p>The Evaluator Agent <strong>V</strong> is an adversarial reviewer.</p><p>Interface: <code>V.evaluate(τ, t)</code> → (report, score)</p><p>Four functions:</p><ol><li><strong>State verification</strong> — cross-references worker observations against ground-truth environment state, detecting hallucinated or misinterpreted states</li><li><strong>Criteria checking</strong> — evaluates final state against each success criterion, producing pass/fail verdicts</li><li><strong>Performance auditing</strong> — decomposes execution time into LLM time versus tool time, identifying computational versus behavioral bottlenecks</li><li><strong>Scoring</strong> — computes two-tier metric: pass/fail first, then execution time as tiebreaker</li></ol><h3 id="_2-5-evolution-agent" tabindex="-1">2.5 Evolution Agent <a class="header-anchor" href="#_2-5-evolution-agent" aria-label="Permalink to &quot;2.5 Evolution Agent&quot;">​</a></h3><p>The Evolution Agent <strong>E</strong> operates as senior engineer.</p><p>Interface: <code>E.evolve(history, ℋ^(best))</code> → ℋ&#39;</p><ol><li><strong>Aggregates diagnostics</strong> — reads full evolution history including tried variants, reports, scores, improvements/regressions</li><li><strong>Identifies failure patterns</strong> — classifies failures into categories (incorrect tool usage, reasoning loops, misinterpreted state, latency)</li><li><strong>Modifies harness</strong> — edits worker harness based on diagnosed failures, including tools, prompts, orchestration, observations, or model configuration</li></ol><hr><h2 id="algorithm-1-the-harness-evolution-loop" tabindex="-1">Algorithm 1: The Harness Evolution Loop <a class="header-anchor" href="#algorithm-1-the-harness-evolution-loop" aria-label="Permalink to &quot;Algorithm 1: The Harness Evolution Loop&quot;">​</a></h2><p><strong>Input</strong>: Task t, Worker Agent W_ℋ, initial harness ℋ^(0), Evaluator V, Evolution Agent E, iterations K</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Initialize ℋ^(best) ← ℋ^(0); best_score ← -∞</span></span>
<span class="line"><span>Initialize history ← []</span></span>
<span class="line"><span></span></span>
<span class="line"><span>For k = 1 to K:</span></span>
<span class="line"><span>    Rebuild W_ℋ^(k-1) from ℋ^(k-1)</span></span>
<span class="line"><span>    Prepare target environment; reset to clean state</span></span>
<span class="line"><span>    trace ← W_ℋ^(k-1).execute(t)</span></span>
<span class="line"><span>    (report, score) ← V.evaluate(trace, t)</span></span>
<span class="line"><span>    If score &gt; best_score: verdict ← improved; update ℋ^(best)</span></span>
<span class="line"><span>    Else: verdict ← regressed</span></span>
<span class="line"><span>    Add (ℋ^(k-1), report, score, verdict) to history</span></span>
<span class="line"><span>    ℋ^(k) ← E.evolve(history, ℋ^(best))</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Return ℋ^(best), best_score, history</span></span></code></pre></div><hr><h2 id="_3-meta-evolution-learning-to-evolve-harnesses" tabindex="-1">3. Meta-Evolution: Learning to Evolve Harnesses <a class="header-anchor" href="#_3-meta-evolution-learning-to-evolve-harnesses" aria-label="Permalink to &quot;3. Meta-Evolution: Learning to Evolve Harnesses&quot;">​</a></h2><p>The harness evolution loop itself—evaluator prompt, evolution agent&#39;s diagnostic strategy, scoring function, observation structure, orchestration logic—is also a harness, denoted <strong>Λ</strong>.</p><p><strong>Λ = (W_ℋ, ℋ^(0), V, E)</strong></p><p>Where:</p><ul><li>W_ℋ is worker agent</li><li>ℋ^(0) is initial worker harness</li><li>V is evaluator agent</li><li>E is evolution agent</li></ul><p>Currently Λ is human-designed and fixed. The framework generalizes by having a Meta-Evolution Agent optimize Λ itself.</p><h3 id="_3-1-the-harness-evolution-loop-as-a-harness" tabindex="-1">3.1 The Harness Evolution Loop as a Harness <a class="header-anchor" href="#_3-1-the-harness-evolution-loop-as-a-harness" aria-label="Permalink to &quot;3.1 The Harness Evolution Loop as a Harness&quot;">​</a></h3><p>Λ has identical structure to any harness: prompts, tools, observations, orchestration logic. Meta-Evolution Agent can modify:</p><ul><li>Evaluator agent prompt (failure modes, grading, evidence requirements)</li><li>Evolution agent prompt (diagnosis, prioritization, modification aggressiveness)</li><li>Worker observation structure (telemetry, traces, intermediate state)</li><li>Evaluator and evolution agent observations (information flow between agents)</li><li>Scoring function design (metric structure, thresholds, tiebreakers)</li><li>Loop hyperparameters (iterations, parallelism, revert thresholds, stopping criteria)</li></ul><h3 id="_3-2-a-meta-learning-formulation" tabindex="-1">3.2 A Meta-Learning Formulation <a class="header-anchor" href="#_3-2-a-meta-learning-formulation" aria-label="Permalink to &quot;3.2 A Meta-Learning Formulation&quot;">​</a></h3><p>Let <strong>𝒯_train = {t_1, t_2, …, t_n}</strong> be meta-train tasks from potentially different domains. Let <strong>𝒯_test</strong> be held-out meta-test tasks for evaluating generalization.</p><p><strong>Two-loop operation:</strong></p><p><strong>Inner loop</strong>: Given fixed blueprint Λ and single task t_i, run harness evolution loop for K iterations producing optimized worker harness ℋ^(K). Measure convergence trajectory.</p><p><strong>Outer loop</strong>: Across tasks t_i ∈ 𝒯_train, evaluate how effectively current Λ drives inner loop. Modify Λ to improve speed of adaptation—rate at which inner loop converges to high performance on single task.</p><p><strong>Objective:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Λ^(best) = arg max_Λ 𝔼_{t_i ~ 𝒯_train}[best_score(HarnessEvolutionLoop(t_i, Λ, K))]</span></span></code></pre></div><p>Blueprint Λ is judged solely by final best score achieved—not intermediate progress.</p><h3 id="algorithm-2-the-meta-evolution-loop" tabindex="-1">Algorithm 2: The Meta-Evolution Loop <a class="header-anchor" href="#algorithm-2-the-meta-evolution-loop" aria-label="Permalink to &quot;Algorithm 2: The Meta-Evolution Loop&quot;">​</a></h3><p><strong>Input</strong>: Meta-train tasks 𝒯_train, Meta-Evolution Agent E_meta, initial blueprint Λ^(0), inner-loop budget K</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Initialize Λ^(best) ← Λ^(0); best_meta_score ← -∞</span></span>
<span class="line"><span>Initialize meta_history ← []</span></span>
<span class="line"><span></span></span>
<span class="line"><span>For j = 0, 1, 2, …:</span></span>
<span class="line"><span>    Initialize task_results ← []</span></span>
<span class="line"><span>    For each task t_i ∈ 𝒯_train:</span></span>
<span class="line"><span>        ℋ_i^(best), best_score_i, history_i ← HarnessEvolutionLoop(t_i, Λ^(j), K)</span></span>
<span class="line"><span>        Add (t_i, best_score_i, history_i) to task_results</span></span>
<span class="line"><span>    meta_score ← Aggregate(task_results) [mean score across tasks]</span></span>
<span class="line"><span>    If meta_score &gt; best_meta_score: verdict ← improved; update Λ^(best)</span></span>
<span class="line"><span>    Else: verdict ← regressed</span></span>
<span class="line"><span>    Add (Λ^(j), task_results, meta_score, verdict) to meta_history</span></span>
<span class="line"><span>    Λ^(j+1) ← E_meta.evolve(meta_history, Λ^(best))</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Return Λ^(best), best_meta_score, meta_history</span></span></code></pre></div><h3 id="_3-3-evaluation-protocol" tabindex="-1">3.3 Evaluation Protocol <a class="header-anchor" href="#_3-3-evaluation-protocol" aria-label="Permalink to &quot;3.3 Evaluation Protocol&quot;">​</a></h3><p>Generalization evaluated on 𝒯_test: given unseen task, how quickly does inner harness evolution loop—configured with learned Λ^(best)—produce high-performing worker harness?</p><p><strong>Key metrics:</strong></p><table tabindex="0"><thead><tr><th>Metric</th><th>Definition</th></tr></thead><tbody><tr><td>Convergence speed</td><td>Iterations to reach target performance threshold</td></tr><tr><td>Final performance</td><td>Task pass rate after fixed iterations</td></tr><tr><td>Robustness</td><td>Variance in convergence speed across meta-test tasks</td></tr></tbody></table><hr><h2 id="correspondence-meta-learning-vs-meta-evolution" tabindex="-1">Correspondence: Meta-Learning vs Meta-Evolution <a class="header-anchor" href="#correspondence-meta-learning-vs-meta-evolution" aria-label="Permalink to &quot;Correspondence: Meta-Learning vs Meta-Evolution&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Meta-Learning</th><th>Meta-Evolution</th></tr></thead><tbody><tr><td>Parameters adapted: θ</td><td>Harness evolved: ℋ</td></tr><tr><td>Adaptation procedure (θ^(0), optimizer, loss)</td><td>Evolution blueprint Λ = (W_ℋ, ℋ^(0), V, E)</td></tr><tr><td>Inner loop: gradient updates on task t_i</td><td>Inner loop: HarnessEvolutionLoop(t_i, Λ, K)</td></tr><tr><td>Outer loop: meta-gradient update</td><td>Outer loop: E_meta.evolve(meta_history, Λ^(best))</td></tr><tr><td>Meta-train tasks</td><td>Training tasks 𝒯_train</td></tr><tr><td>Meta-test tasks</td><td>Held-out tasks 𝒯_test</td></tr><tr><td>Objective: fast adaptation to new tasks</td><td>Objective: fast harness convergence on new tasks</td></tr></tbody></table><hr><h2 id="_4-conclusion" tabindex="-1">4. Conclusion <a class="header-anchor" href="#_4-conclusion" aria-label="Permalink to &quot;4. Conclusion&quot;">​</a></h2><p>The Harness Evolution Loop automatically optimizes an AI agent&#39;s harness—prompts, tools, orchestration logic, infrastructure—through repeated task execution, adversarial evaluation, and code modification. The system formalizes agents as W_ℋ, separates evaluation (V) from evolution (E), and iteratively improves ℋ while tracking convergence history.</p><p>The Meta-Evolution Loop optimizes evolution blueprint Λ itself across diverse tasks. By running inner harness evolution loop on each training task and measuring convergence, meta-evolution agent E_meta learns blueprint Λ^(best) enabling rapid adaptation to unseen tasks.</p><p>Where harness engineering traditionally required &quot;deep human expertise applied to each specific task domain,&quot; the Harness Evolution Loop automates entirely—transforming manual harness engineering into automated harness engineering. The Meta-Evolution Loop goes further: automating design of the automation itself, learning how to evolve harnesses rather than evolving any single harness.</p><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Anthropic (2025) Claude code: best practices for agentic coding</li><li>Guo, Y., et al. (2026) OpAgent: operator agent for web navigation</li><li>Lopopolo, R. (2026) Harness engineering: leveraging Codex in an agent-first world</li><li>OpenAI (2025) Introducing Codex</li><li>Rajasekaran, P. (2026) Harness design for long-running application development</li><li>SylphAI (2026) AdaL: the self-evolving AI coding agent</li><li>Thrun, S. and Pratt, L. (1998) Learning to learn. Springer</li><li>Trivedy, V. (2026) The anatomy of an agent harness</li><li>Yin, L. and Wang, Z. (2025) LLM-AutoDiff: auto-differentiate any LLM workflow</li><li>Zhou, S., et al. (2024) WebArena: a realistic web environment for building autonomous agents. ICLR</li></ul><hr><h2 id="workspace-alignment-analysis" tabindex="-1">Workspace Alignment Analysis <a class="header-anchor" href="#workspace-alignment-analysis" aria-label="Permalink to &quot;Workspace Alignment Analysis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Paper Concept</th><th>cc-workspace Current State</th><th>Opportunity</th></tr></thead><tbody><tr><td>Adversarial evaluation</td><td>Manual <code>/deep-review</code></td><td>Add adversarial test case generation step</td></tr><tr><td>Meta-Evolution blueprint</td><td>session-learner skill</td><td>Integrate cross-session pattern learning</td></tr><tr><td>Targeted modification</td><td>Known Gotchas → rule upgrade</td><td>Quantify upgrade threshold decisions</td></tr><tr><td>Generator ≠ Evaluator</td><td>PGE principle in core.md</td><td>✅ Already aligned</td></tr></tbody></table><p><strong>Manual vs Automated Ratchet Comparison:</strong></p><table tabindex="0"><thead><tr><th>Manual Ratchet (cc-workspace)</th><th>Automated Meta-Evolution (this paper)</th></tr></thead><tbody><tr><td>Record Known Gotchas manually after incidents</td><td>Adversarial evaluator auto-discovers weaknesses</td></tr><tr><td>Human decides rule → hook escalation</td><td>Meta-learner auto-learns escalation patterns</td></tr><tr><td>Each change requires manual verification</td><td>Evolution Loop auto-verifies</td></tr><tr><td>Cross-task experience via session notes</td><td>Meta-Blueprint auto-transfers cross-task</td></tr></tbody></table><p>Integration targets: <code>/deep-review</code> adversarial step + <code>session-learner</code> skill + <code>RATCHET.md</code></p>`,79)])])}const g=t(o,[["render",r]]);export{u as __pageData,g as default};
